import{_ as a,c as t,o as r,aj as i}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"Operations","description":"","frontmatter":{},"headers":[],"relativePath":"guide/best-practices/operations.md","filePath":"guide/best-practices/operations.md","lastUpdated":1777621302000}'),o={name:"guide/best-practices/operations.md"};function n(s,e,l,c,d,h){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="operations" tabindex="-1">Operations <a class="header-anchor" href="#operations" aria-label="Permalink to &quot;Operations&quot;">​</a></h1><p>Operational readiness means that the network can be observed, changed, backed up, and recovered without relying on improvised access to validator hosts.</p><h2 id="observability" tabindex="-1">Observability <a class="header-anchor" href="#observability" aria-label="Permalink to &quot;Observability&quot;">​</a></h2><ul><li>Enable telemetry profiles intentionally. Use <code>extended</code> when <code>/metrics</code> is needed and <code>full</code> during test runs that need detailed Sumeragi operator routes.</li><li>Dashboard accepted throughput, rejected throughput, commit latency, queue depth, queue saturation, view changes, dropped consensus messages, and storage pressure.</li><li>Keep status snapshots, metrics scrapes, logs, and deployment configuration in the same incident or benchmark artifact set.</li><li>Alert on sustained queue growth, unexpected rejection spikes, stalled block height, view-change churn, and peer health changes.</li></ul><p>See <a href="/iroha-2-docs/guide/advanced/metrics.html">Performance and Metrics</a>.</p><h2 id="runbooks" tabindex="-1">Runbooks <a class="header-anchor" href="#runbooks" aria-label="Permalink to &quot;Runbooks&quot;">​</a></h2><ul><li>Write runbooks for peer restart, Torii degradation, key compromise, permission mistakes, fee sponsor depletion, stuck queues, and network partition symptoms.</li><li>Include exact read-only checks before write operations, especially for peer registration, permission grants, and parameter changes.</li><li>Keep emergency contacts and escalation rules outside the docs repo if they include private operational data.</li><li>Review runbooks after every incident, rehearsal, or major upgrade.</li></ul><p>See <a href="/iroha-2-docs/guide/security/operational-security.html">Operational Security</a>.</p><h2 id="backups-and-recovery" tabindex="-1">Backups and Recovery <a class="header-anchor" href="#backups-and-recovery" aria-label="Permalink to &quot;Backups and Recovery&quot;">​</a></h2><ul><li>Back up peer storage according to the recovery point required by the deployment. Validate restores on non-production hosts.</li><li>Keep signed genesis, release metadata, peer config, and key custody records recoverable even if a validator host is unavailable.</li><li>Document whether a recovery procedure rebuilds from genesis, restores from a snapshot, or replaces a failed peer with a new identity.</li><li>Never test restore procedures for the first time during a production incident.</li></ul><h2 id="change-management" tabindex="-1">Change Management <a class="header-anchor" href="#change-management" aria-label="Permalink to &quot;Change Management&quot;">​</a></h2><ul><li>Treat on-chain configuration changes as transactions that require review, preflight reads, authorization, and post-change verification.</li><li>Roll out peer binary upgrades with a compatibility plan and a rollback decision point.</li><li>Avoid changing peer topology, consensus timing, and application workload in the same maintenance window unless the migration plan requires it.</li><li>Record the transaction hashes and block heights for operational changes.</li></ul><p>See <a href="/iroha-2-docs/guide/advanced/hot-reload.html">Hot Reload</a> and <a href="/iroha-2-docs/reference/compatibility-matrix.html">Compatibility Matrix</a>.</p><h2 id="capacity-reviews" tabindex="-1">Capacity Reviews <a class="header-anchor" href="#capacity-reviews" aria-label="Permalink to &quot;Capacity Reviews&quot;">​</a></h2><ul><li>Re-run load checks when validator count, hardware, network placement, workload mix, or consensus parameters change.</li><li>Measure warm-up, steady state, and expected peak load rather than relying on a short best-case throughput sample.</li><li>Compare accepted throughput with committed throughput and queue depth. If submitted TPS exceeds committed TPS and queues grow, the network is past its sustainable envelope.</li></ul>',15)])])}const m=a(o,[["render",n]]);export{u as __pageData,m as default};
